# coding=UTF-8
# ex:ts=4:sw=4:et=on

import numpy as np

import gi
gi.require_version('Gtk', '3.0')
from gi.repository import Gtk

from mvc.adapters.gtk_support.dialogs.dialog_factory import DialogFactory
from mudlab.generic.controllers import BaseController
from mudlab.generic.controllers.dialog_controller import DialogController


class TrimController(DialogController):
    """
    Controller for the Trim Specimen dialog.

    Permanently clips experimental (and computed calculated) data to a
    user-specified 2-theta range, removing any markers and exclusion ranges
    that fall outside the new limits.

    Parameters
    ----------
    specimens : list
        All specimens loaded in the current project.
    current_specimen : Specimen
        The specimen that is currently selected. Used to pre-fill the
        range inputs and as the target when scope is "This specimen only".
    """

    def __init__(self, specimens, current_specimen, view, parent=None):
        # DialogController expects a model; we pass current_specimen as the
        # model so the MVC machinery is satisfied, but we manage everything
        # manually — auto_adapt is disabled.
        super(TrimController, self).__init__(
            model=current_specimen,
            view=view,
            parent=parent,
            auto_adapt=False,
        )
        self._specimens = specimens
        self._current_specimen = current_specimen

    # ------------------------------------------------------------------
    #   Setup
    # ------------------------------------------------------------------

    def register_view(self, view):
        super(TrimController, self).register_view(view)
        self._setup_range_from_specimen(self._current_specimen)
        view['cmb_scope'].set_active(0)
        self._connect_signals()
        self._update_warning()

    def _setup_range_from_specimen(self, specimen):
        """Pre-fill min/max spin buttons from specimen's experimental data range."""
        data_x = specimen.experimental_pattern.data_x
        if data_x is not None and len(data_x) >= 2:
            data_min = float(np.min(data_x))
            data_max = float(np.max(data_x))
        else:
            data_min, data_max = 0.0, 180.0
        self._set_spin_limits(data_min, data_max)
        self.view['spin_min_2theta'].set_value(data_min)
        self.view['spin_max_2theta'].set_value(data_max)

    def _set_spin_limits(self, lo, hi):
        """Update the adjustment limits so the spinbuttons can't go out of range."""
        adj_min = self.view['adj_min_2theta']
        adj_max = self.view['adj_max_2theta']
        # Allow the user to enter any value within [0, 180]; the current
        # data bounds are just the default values.
        adj_min.set_lower(0.0)
        adj_min.set_upper(hi)
        adj_max.set_lower(lo)
        adj_max.set_upper(180.0)

    def _connect_signals(self):
        self.view['cmb_scope'].connect('changed', self._on_scope_changed)
        self.view['spin_min_2theta'].connect('value-changed', self._on_range_changed)
        self.view['spin_max_2theta'].connect('value-changed', self._on_range_changed)

    # ------------------------------------------------------------------
    #   Signal handlers (private)
    # ------------------------------------------------------------------

    def _on_scope_changed(self, combo):
        if combo.get_active() == 1:  # "All loaded specimens"
            # Pre-fill with intersection of all specimen ranges
            mins, maxs = [], []
            for sp in self._specimens:
                dx = sp.experimental_pattern.data_x
                if dx is not None and len(dx) >= 2:
                    mins.append(float(np.min(dx)))
                    maxs.append(float(np.max(dx)))
            if mins:
                intersection_min = max(mins)   # widest lower bound
                intersection_max = min(maxs)   # narrowest upper bound
                if intersection_min < intersection_max:
                    self._set_spin_limits(intersection_min, intersection_max)
                    self.view['spin_min_2theta'].set_value(intersection_min)
                    self.view['spin_max_2theta'].set_value(intersection_max)
        else:  # "This specimen only"
            self._setup_range_from_specimen(self._current_specimen)
        self._update_warning()

    def _on_range_changed(self, spin):
        self._update_warning()

    # ------------------------------------------------------------------
    #   Warning label
    # ------------------------------------------------------------------

    def _count_removals(self, specimen, min_2t, max_2t):
        """Return (n_markers, n_excl_ranges) that would be removed."""
        n_markers = sum(
            1 for m in specimen.markers
            if m.position < min_2t or m.position > max_2t
        )
        x0_arr, x1_arr = specimen.exclusion_ranges.get_xy_data()
        if len(x0_arr) > 0:
            outside = ~((x0_arr >= min_2t) & (x1_arr <= max_2t))
            n_excl = int(np.sum(outside))
        else:
            n_excl = 0
        return n_markers, n_excl

    def _update_warning(self):
        min_2t = self.view['spin_min_2theta'].get_value()
        max_2t = self.view['spin_max_2theta'].get_value()
        scope = self.view['cmb_scope'].get_active()

        targets = self._specimens if scope == 1 else [self._current_specimen]

        total_markers = 0
        total_excl = 0
        for sp in targets:
            nm, ne = self._count_removals(sp, min_2t, max_2t)
            total_markers += nm
            total_excl += ne

        lbl = self.view['lbl_removal_warning']
        parts = []
        if total_markers:
            parts.append("%d marker%s" % (total_markers, "s" if total_markers != 1 else ""))
        if total_excl:
            parts.append("%d exclusion range%s" % (total_excl, "s" if total_excl != 1 else ""))

        if parts:
            lbl.set_text("The following will also be removed: %s." % " and ".join(parts))
            lbl.show()
        else:
            lbl.hide()

    # ------------------------------------------------------------------
    #   OK / Cancel
    # ------------------------------------------------------------------

    def on_btn_ok_clicked(self, event):
        min_2t = self.view['spin_min_2theta'].get_value()
        max_2t = self.view['spin_max_2theta'].get_value()
        scope  = self.view['cmb_scope'].get_active()

        if min_2t >= max_2t:
            DialogFactory.get_information_dialog(
                "Min °2\u03b8 must be less than Max °2\u03b8.",
                parent=self.view.get_top_widget()
            ).run()
            return True

        targets = self._specimens if scope == 1 else [self._current_specimen]

        failed = []
        for sp in targets:
            if not sp.trim(min_2t, max_2t):
                failed.append(sp.name or "(unnamed)")

        if failed:
            DialogFactory.get_information_dialog(
                "The following specimen(s) could not be trimmed because the "
                "selected range contains fewer than 2 data points:\n%s"
                % "\n".join(failed),
                parent=self.view.get_top_widget()
            ).run()

        return super(TrimController, self).on_btn_ok_clicked(event)

    pass  # end of class
